s3 = boto3.client("s3", region_name=AWS_REGION, endpoint_url=AWS_S3_ENDPOINT or None)

url_lock = threading.Lock()
inflight = {}

def is_valid_url(url):
    try:
        parsed = urlparse(url)
        if parsed.scheme not in ("http", "https"):
            return False
        if not parsed.netloc:
            return False
        host = parsed.hostname or ""
        if not ALLOW_PRIVATE_NETWORK:
            if host in ("localhost",):
                return False
            if re.match(r"^(127\.|10\.|192\.168\.|172\.(1[6-9]|2\d|3[0-1])\.)", host):
                return False
        return True
    except Exception:
        return False

def s3_key_for_url(url):
    h = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{h}.png"

def s3_thumb_key_for_url(url):
    h = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{h}_thumb.jpg"

def object_exists(key):
    try:
        s3.head_object(Bucket=S3_BUCKET, Key=key)
        return True
    except Exception:
        return False

def upload_bytes(key, data, content_type):
    s3.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=data,
        ContentType=content_type,
        CacheControl=CACHE_CONTROL,
    )

def download_bytes(key):
    obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
    return obj["Body"].read()

def get_browser_driver():
    if webdriver is None:
        raise RuntimeError("selenium not available")
    if USE_PHANTOMJS:
        phantom = PHANTOMJS_BIN
        if not os.path.exists(phantom):
            raise RuntimeError("phantomjs binary not found")
        return webdriver.PhantomJS(executable_path=phantom)
    chrome_bin = CHROME_BIN if os.path.exists(CHROME_BIN) else CHROMIUM_BIN
    if not os.path.exists(chrome_bin):
        raise RuntimeError("chrome/chromium binary not found")
    options = ChromeOptions()
    options.binary_location = chrome_bin
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument(f"--window-size={SCREENSHOT_WIDTH},{SCREENSHOT_HEIGHT}")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--disable-web-security")
    options.add_argument("--allow-running-insecure-content")
    options.add_argument("--disable-features=IsolateOrigins,site-per-process")
    options.add_argument("--force-device-scale-factor=1")
    service = ChromeService()
    return webdriver.Chrome(service=service, options=options)

def capture_screenshot(url):
    driver = get_browser_driver()
    try:
        driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
        driver.get(url)
        time.sleep(2)
        try:
            driver.execute_script("window.scrollTo(0, 0);")
        except Exception:
            pass
        png = driver.get_screenshot_as_png()
        return png
    finally:
        try:
            driver.quit()
        except Exception:
            pass

def make_thumbnail(image_bytes):
    if not ENABLE_THUMBNAIL:
        return image_bytes, "image/png"
    if Image is None:
        return image_bytes, "image/png"
    img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    img.thumbnail((THUMB_WIDTH, THUMB_HEIGHT))
    out = io.BytesIO()
    img.save(out, format="JPEG", quality=85, optimize=True)
    return out.getvalue(), "image/jpeg"

def generate_and_store(url):
    png = capture_screenshot(url)
    key = s3_key_for_url(url)
    upload_bytes(key, png, "image/png")
    thumb_bytes, thumb_ct = make_thumbnail(png)
    thumb_key = s3_thumb_key_for_url(url)
    upload_bytes(thumb_key, thumb_bytes, thumb_ct)
    return key, thumb_key

def get_or_create(url):
    key = s3_key_for_url(url)
    thumb_key = s3_thumb_key_for_url(url)
    if object_exists(key) and object_exists(thumb_key):
        return key, thumb_key, False
    lock_key = hashlib.sha256(url.encode("utf-8")).hexdigest()
    with url_lock:
        lock = inflight.get(lock_key)
        if lock is None:
            lock = threading.Lock()
            inflight[lock_key] = lock
    with lock:
        try:
            if object_exists(key) and object_exists(thumb_key):
                return key, thumb_key, False
            return (*generate_and_store(url), True)
        finally:
            with url_lock:
                inflight.pop(lock_key, None)

