@app.route("/screenshot", methods=["POST", "GET"])
def screenshot():
    url = request.values.get("url", "").strip()
    if not url or not is_valid_url(url):
        return jsonify({"error": "invalid_url"}), 400
    try:
        key, thumb_key, created = get_or_create(url)
        return jsonify({
            "url": url,
            "created": created,
            "screenshot_key": key,
            "thumbnail_key": thumb_key,
            "screenshot_url": f"/image?key={quote_plus(key)}",
            "thumbnail_url": f"/thumbnail?key={quote_plus(thumb_key)}",
        })
    except Exception as e:
        return jsonify({"error": "capture_failed", "message": str(e)}), 500

@app.route("/image", methods=["GET"])
def image():
    key = request.args.get("key", "").strip()
    if not key:
        abort(400)
    try:
        data = download_bytes(key)
        return send_file(io.BytesIO(data), mimetype="image/png", as_attachment=False, download_name=os.path.basename(key))
    except Exception:
        abort(404)

@app.route("/thumbnail", methods=["GET"])
def thumbnail():
    key = request.args.get("key", "").strip()
    if not key:
        abort(400)
    try:
        obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
        data = obj["Body"].read()
        ct = obj.get("ContentType", "image/jpeg")
        return send_file(io.BytesIO(data), mimetype=ct, as_attachment=False, download_name=os.path.basename(key))
    except Exception:
        abort(404)

@app.route("/preview", methods=["GET"])
def preview():
    url = request.args.get("url", "").strip()
    if not url or not is_valid_url(url):
        return jsonify({"error": "invalid_url"}), 400
    try:
        _, thumb_key, _ = get_or_create(url)
        signed = s3.generate_presigned_url(
            "get_object",
            Params={"Bucket": S3_BUCKET, "Key": thumb_key},
            ExpiresIn=3600,
        )
        return jsonify({"url": url, "thumbnail": signed, "key": thumb_key})
    except Exception as e:
        return jsonify({"error": "preview_failed", "message": str(e)}), 500

